where.trim:
AND c.store_id = #{storeId}
AND c.recycle = 0
and c.living_id = #{room_id}
AND a.product_class like CONCAT('%-',
    #{product_class},'-%')

AND a.brand_id = #{brand_id}
AND (a.product_title like CONCAT('%',
    #{product_title},'%') or a.id = #{product_title})

AND b.name like CONCAT('%', #{mch_name},'%')

mapper.select:
SELECT
a.update_time, a.living_id, a.mch_name FROM ( SELECT
c.add_time AS update_time, c.store_id as c_storeId, c.recycle as c_recycle, c.living_id, ifnull( b.NAME, '' ) AS mch_name, ROW_NUMBER() over(partition by a.id ORDER BY c.add_time DESC, c.id DESC) AS top FROM lkt_living_product c LEFT JOIN lkt_product_list a ON c.pro_id = a.id LEFT JOIN lkt_mch AS b ON a.mch_id = b.id
) AS a where a.top <2 LIMIT #{page},#{pageSize}

SELECT
a.mch_name, a.commission, a.kucun, a.update_time FROM ( SELECT a.*, ifnull( m.NAME, '' ) AS mch_name, b.commission, b.num as kucun, date_format( b.update_time, '%Y-%m-%d %H:%i:%s' ) AS update_time, ROW_NUMBER() over (partition by a.id ORDER BY b.update_time DESC, b.id DESC) AS top FROM lkt_product_list a LEFT JOIN lkt_configure b ON a.id = b.pid LEFT JOIN lkt_mch m ON m.id = a.mch_id
) AS a WHERE a.top < 2 order by a.id desc LIMIT #{page},#{pageSize}

SELECT
a.update_time, a.sort_num, a.add_time FROM ( SELECT a.*, ifnull( m.NAME, "" ) AS mchName, date_format( b.update_time, '%Y-%m-%d %H:%i:%s' ) AS update_time, l.sort_num, date_format( l.add_time, '%Y-%m-%d %H:%i:%s' ) AS add_time, ROW_NUMBER() over(partition by a.id ORDER BY l.sort ASC, l.sort_num ASC, l.id DESC) AS top, l.recycle as l_recycle, b.commission, l.living_id, l.sort as l_sort FROM lkt_living_product l LEFT JOIN lkt_product_list a ON l.pro_id = a.id LEFT JOIN lkt_configure b ON l.config_id = b.id LEFT JOIN lkt_mch m ON m.id = a.mch_id
order by l.sort asc,l.sort_num asc ) AS a where a.top <2 LIMIT #{page},#{pageSize}

SELECT
a.mchName, a.represent, a.sort_num, a.l_sort, a.commission, a.living_id, l_recycle FROM ( SELECT a.*, ifnull( m.NAME, '' ) AS mchName, l.represent, l.sort_num, l.sort as l_sort, b.commission, l.living_id, l.recycle as l_recycle, ROW_NUMBER() over(partition by a.id ORDER BY l.represent DESC, l.sort ASC, l.sort_num ASC, l.id DESC) AS top FROM lkt_living_product l LEFT JOIN lkt_product_list a ON l.pro_id = a.id LEFT JOIN lkt_configure b ON l.config_id = b.id LEFT JOIN lkt_mch m ON m.id = a.mch_id
order by l.represent desc,l.sort asc,l.sort_num ) AS a WHERE a.top < 2 LIMIT #{page},#{pageSize}
